export type RetentionPolicy = { max_versions: number; naming: VersionNaming }
export type S3Config = { provider: string; bucket: string; region: string; access_key_id: string; secret_access_key: string; endpoint_url: string | null; prefix: string }
export type Schedule = { type: "Interval"; value: { minutes: number } } | { type: "Cron"; value: { expression: string } } | { type: "OnChange" } | { type: "Manual" }
export type SftpConfig = { host: string; port: number; username: string; auth_type: string; password: string | null; private_key: string | null; remote_path: string }
export type Source = { id: string; name: string; path: string; source_type: SourceType; enabled: boolean; created_at: string; destinations: Destination[] }
export type SourceType = "File" | "Directory"
export type UpdateInfo = { available: boolean; version: string | null; body: string | null }
export type ValidateResult = { status: string; offline: boolean | null; cached: boolean | null }
export type VaultEntry = { id: string; name: string; parent_id: string | null; kind: EntryKind; 
/**
 * Bayt cinsinden boyut (sadece dosyalar)
 */
size: number | null; modified: string | null; 
/**
 * Dosya şifreleme nonce'u (hex), sadece dosyalar
 */
nonce: string | null }
export type VaultSummary = { id: string; name: string; algorithm: string; vault_path: string; created_at: string; last_opened: string | null; unlocked: boolean }
export type VersionNaming = "Timestamp" | "Index" | "Overwrite"
export type WebDavConfig = { url: string; username: string; password: string; root_path: string }

/** tauri-specta globals **/

import {
	invoke as TAURI_INVOKE,
	Channel as TAURI_CHANNEL,
} from "@tauri-apps/api/core";
import * as TAURI_API_EVENT from "@tauri-apps/api/event";
import { type WebviewWindow as __WebviewWindow__ } from "@tauri-apps/api/webviewWindow";

type __EventObj__<T> = {
	listen: (
		cb: TAURI_API_EVENT.EventCallback<T>,
	) => ReturnType<typeof TAURI_API_EVENT.listen<T>>;
	once: (
		cb: TAURI_API_EVENT.EventCallback<T>,
	) => ReturnType<typeof TAURI_API_EVENT.once<T>>;
	emit: null extends T
		? (payload?: T) => ReturnType<typeof TAURI_API_EVENT.emit>
		: (payload: T) => ReturnType<typeof TAURI_API_EVENT.emit>;
};

export type Result<T, E> =
	| { status: "ok"; data: T }
	| { status: "error"; error: E };

function __makeEvents__<T extends Record<string, any>>(
	mappings: Record<keyof T, string>,
) {
	return new Proxy(
		{} as unknown as {
			[K in keyof T]: __EventObj__<T[K]> & {
				(handle: __WebviewWindow__): __EventObj__<T[K]>;
			};
		},
		{
			get: (_, event) => {
				const name = mappings[event as keyof T];

				return new Proxy((() => {}) as any, {
					apply: (_, __, [window]: [__WebviewWindow__]) => ({
						listen: (arg: any) => window.listen(name, arg),
						once: (arg: any) => window.once(name, arg),
						emit: (arg: any) => window.emit(name, arg),
					}),
					get: (_, command: keyof __EventObj__<any>) => {
						switch (command) {
							case "listen":
								return (arg: any) => TAURI_API_EVENT.listen(name, arg);
							case "once":
								return (arg: any) => TAURI_API_EVENT.once(name, arg);
							case "emit":
								return (arg: any) => TAURI_API_EVENT.emit(name, arg);
						}
					},
				});
			},
		},
	);
}
